import SwiftUI

enum Direction: Int {
    case up, down, left, right 
}

struct ContentView: View {
    @State private var squarePosition = CGSize(width: 50, height: 50)

    var body: some View {
        Rectangle()
            .fill(Color.blue)
            .frame(width: 100, height: 100)
            .position(x: 100, y: 100)
            .focusable()
            .onAppear { UIApplication.shared.isIdleTimerDisabled = true }
            .onDisappear { UIApplication.shared.isIdleTimerDisabled = false }
            .onKeyDown { event in
                guard let direction = Direction(rawValue: event.key.keyCode) else { return }
                squarePosition = moveSquare(direction: direction)
            }
    }

    private func moveSquare(direction: Direction) -> CGSize {
        let step: CGFloat = 10

        switch direction {
        case .up:
            return CGSize(width: squarePosition.width, height: squarePosition.height - step)
        case .down:
            return CGSize(width: squarePosition.width, height: squarePosition.height + step)
        case .left:
            return CGSize(width: squarePosition.width - step, height: squarePosition.height)
        case .right:
            return CGSize(width: squarePosition.width + step, height: squarePosition.height)
        }
    }
}

